local Rayfield=loadstring(game:HttpGet("https://sirius.menu/rayfield"))()

-- Services
local Players=game:GetService("Players")
local Workspace=game:GetService("Workspace")
local ReplicatedStorage=game:GetService("ReplicatedStorage")
local VirtualInputManager=game:GetService("VirtualInputManager")
local VirtualUser=game:GetService("VirtualUser")
local TeleportService=game:GetService("TeleportService")

local LocalPlayer=Players.LocalPlayer
local PlaceId=game.PlaceId

-- Combat Remotes
local Net=ReplicatedStorage:WaitForChild("Modules"):WaitForChild("Net")
local RegisterAttack=Net["RE/RegisterAttack"]
local RegisterHit=Net["RE/RegisterHit"]
local CommF = ReplicatedStorage:WaitForChild("Remotes"):WaitForChild("CommF")

-- May differ by build
local AddPointRemote=ReplicatedStorage:FindFirstChild("Remotes")
and ReplicatedStorage.Remotes:FindFirstChild("AddPoint")

local HIT_TOKEN="064e1aa1"

------------------------------------------------
-- CONFIG
------------------------------------------------

local Config={

AutoFarm=false,
AutoQuest=false,

FastAttack=false,
AutoSkill=false,
BringMob=false,

AutoM1=false,
AutoHaki=false,
AutoChest=false,

AutoStat=false,
StatType="Melee",

AutoEquip=false,
WeaponName="Combat",

KillAuraLite=false,

SelectedMob="Bandit",
SavedQuestNPC=nil,

FarmDistance=6,
LoopDelay=.2,

AntiAFK=true,

SessionRefresh=false,
RefreshMinutes=15,

AutoStuckFix=true,

Running=true
}

-- Quest Mapping Table
local QuestMap = {
    ["Bandit"] = {"BanditQuest1", 1},
    ["Monkey"] = {"MonkeyQuest1", 1},
    ["Gorilla"] = {"MonkeyQuest1", 2},
    ["Pirate"] = {"BuggyQuest1", 1},
    ["Brute"] = {"BuggyQuest1", 2},
    ["Desert Bandit"] = {"DesertQuest", 1},
    ["Desert Officer"] = {"DesertQuest", 2},
    ["Snow Bandit"] = {"SnowQuest", 1},
    ["Snowman"] = {"SnowQuest", 2},
}

local LastRefresh=os.clock()
Config.LastPos=nil
Config.LastMoveTick=os.clock()

------------------------------------------------
-- CHARACTER
------------------------------------------------

local function char()
return LocalPlayer.Character or LocalPlayer.CharacterAdded:Wait()
end

local function hrp()
return char():FindFirstChild("HumanoidRootPart")
end

-- Check if player already has a quest
local function hasQuest()
    local mainGui = LocalPlayer.PlayerGui:FindFirstChild("Main")
    if mainGui and mainGui:FindFirstChild("Quest") then
        return mainGui.Quest.Visible
    end
    return false
end

------------------------------------------------
-- ANTI AFK
------------------------------------------------

LocalPlayer.Idled:Connect(function()

if not Config.AntiAFK then
return
end

pcall(function()
VirtualUser:CaptureController()
VirtualUser:ClickButton2(Vector2.new())
end)

end)

------------------------------------------------
-- MOB SCANNER
------------------------------------------------

local MobList={"Bandit"}

local function scanMobs()

local found={}
local folder=Workspace:FindFirstChild("Enemies")

if not folder then
return {"Bandit"}
end

for _,mob in ipairs(folder:GetChildren()) do
if not table.find(found,mob.Name) then
table.insert(found,mob.Name)
end
end

table.sort(found)

if #found==0 then
found={"Bandit"}
end

return found

end

------------------------------------------------
-- TARGET
------------------------------------------------

local function getTarget()

local root=hrp()
local folder=Workspace:FindFirstChild("Enemies")

if not root or not folder then
return nil
end

local best=nil
local dist=nil

for _,mob in ipairs(folder:GetChildren()) do

local hum=mob:FindFirstChildOfClass("Humanoid")
local rp=mob:FindFirstChild("HumanoidRootPart")

if mob.Name==Config.SelectedMob
and hum and hum.Health>0 and rp then

local d=(rp.Position-root.Position).Magnitude

if not dist or d<dist then
dist=d
best=mob
end

end
end

return best
end

local function moveToMob(mob)

local root=hrp()
local rp=mob and mob:FindFirstChild("HumanoidRootPart")

if root and rp then
root.CFrame=rp.CFrame*CFrame.new(0,0,Config.FarmDistance)
end

end

local function bringMob(mob)

if not Config.BringMob then return end

local root=hrp()
local rp=mob and mob:FindFirstChild("HumanoidRootPart")

if root and rp then
rp.CFrame=root.CFrame*CFrame.new(0,0,-4)
end

end

------------------------------------------------
-- COMBAT
------------------------------------------------

local function remoteAttack(target)

pcall(function()

RegisterAttack:FireServer(
Config.FastAttack and .15 or .5
)

local part=target and target:FindFirstChild(
"HumanoidRootPart"
)

if part then
RegisterHit:FireServer(
part,
{},
HIT_TOKEN
)
end

end)

end

local function useSkills()

pcall(function()

for _,k in ipairs({"Z","X","C"}) do

VirtualInputManager:SendKeyEvent(
true,k,false,game
)

task.wait(.05)

VirtualInputManager:SendKeyEvent(
false,k,false,game
)

end

end)

end

local function doM1()

pcall(function()

VirtualInputManager:SendMouseButtonEvent(
0,0,0,true,game,0
)

task.wait(.05)

VirtualInputManager:SendMouseButtonEvent(
0,0,0,false,game,0
)

end)

end

local function enableHaki()

pcall(function()

VirtualInputManager:SendKeyEvent(
true,"J",false,game
)

task.wait(.05)

VirtualInputManager:SendKeyEvent(
false,"J",false,game
)

end)

end

------------------------------------------------
-- EXTRA FEATURES
------------------------------------------------

local function chestFarm()

for _,v in ipairs(
Workspace:GetDescendants()
) do

if tostring(v.Name):lower():find("chest") then

local p=v:IsA("BasePart")
and v
or v:FindFirstChildWhichIsA("BasePart")

if p and hrp() then
hrp().CFrame=p.CFrame*CFrame.new(0,3,0)
break
end

end
end

end

local function spendStats()

if not AddPointRemote then return end

pcall(function()
AddPointRemote:InvokeServer(
Config.StatType,
1
)
end)

end

local function equipWeapon()

pcall(function()

local bp=
LocalPlayer.Backpack:FindFirstChild(
Config.WeaponName
)

if bp then
bp.Parent=char()
end

end)

end

local function teleportToSelectedMob()

local t=getTarget()

if t then
moveToMob(t)
end

end

local function killAuraLite()

local root=hrp()
local folder=Workspace:FindFirstChild("Enemies")

if not root or not folder then return end

for _,mob in ipairs(folder:GetChildren()) do

local rp=mob:FindFirstChild("HumanoidRootPart")
local hum=mob:FindFirstChildOfClass("Humanoid")

if rp and hum and hum.Health>0 then

if (rp.Position-root.Position).Magnitude<18 then
remoteAttack(mob)
end

end
end

end

------------------------------------------------
-- QUEST (FIXED)
------------------------------------------------

local function findNearestQuestNPC()

local root=hrp()
if not root then return nil end

local best=nil
local dist=nil

for _,obj in ipairs(
Workspace:GetDescendants()
) do

if obj:IsA("ProximityPrompt") then

local model=obj.Parent and obj.Parent.Parent

if model and model:IsA("Model") then

local rp=
model:FindFirstChild("HumanoidRootPart")
or model:FindFirstChildWhichIsA("BasePart")

if rp then

local d=(
rp.Position-root.Position
).Magnitude

if not dist or d<dist then
dist=d
best=model
end

end
end
end
end

return best

end

local function useQuestNPC()
    if hasQuest() then return end

    local questData = QuestMap[Config.SelectedMob]
    if questData then
        pcall(function()
            CommF:InvokeServer("StartQuest", questData[1], questData[2])
        end)
    else
        -- Fallback to original method if mob isn't in table
        if not Config.SavedQuestNPC then
            Config.SavedQuestNPC = findNearestQuestNPC()
        end

        local npc = Config.SavedQuestNPC
        if not npc then return end

        local part = npc:FindFirstChild("HumanoidRootPart") or npc:FindFirstChildWhichIsA("BasePart")
        if not part then return end

        pcall(function()
            hrp().CFrame = part.CFrame * CFrame.new(0, 0, 4)
            for _, v in ipairs(npc:GetDescendants()) do
                if v:IsA("ProximityPrompt") then
                    fireproximityprompt(v)
                end
            end
        end)
    end
end

------------------------------------------------
-- STABILITY
------------------------------------------------

local function sessionRefresh()

if not Config.SessionRefresh then
return
end

if (os.clock()-LastRefresh)/60
>=Config.RefreshMinutes then

pcall(function()
TeleportService:Teleport(
PlaceId,
LocalPlayer
)
end)

LastRefresh=os.clock()

end

end

local function stuckFix()

if not Config.AutoStuckFix then
return
end

local root=hrp()
if not root then return end

if Config.LastPos then

local moved=(
root.Position-Config.LastPos
).Magnitude

if moved<2 then

if os.clock()-Config.LastMoveTick>30 then
root.CFrame=root.CFrame*CFrame.new(
0,15,0
)
Config.LastMoveTick=os.clock()
end

else

Config.LastMoveTick=os.clock()

end
end

Config.LastPos=root.Position

end

