task.spawn(function()

while Config.Running do

if Config.AutoQuest and not hasQuest() then
    useQuestNPC()
end

if Config.AutoFarm then

local target=getTarget()

if target then

moveToMob(target)

bringMob(target)

remoteAttack(target)

if Config.AutoSkill then
useSkills()
end

end
end

if Config.AutoM1 then
doM1()
end

if Config.AutoHaki then
enableHaki()
end

if Config.AutoChest then
chestFarm()
end

if Config.KillAuraLite then
killAuraLite()
end

if Config.AutoEquip then
equipWeapon()
end

