local QuestMap = {
    ["Bandit"] = {"BanditQuest1",1},
    ["Monkey"] = {"MonkeyQuest1",1},
    ["Gorilla"] = {"MonkeyQuest1",2},
    ["Pirate"] = {"BuggyQuest1",1},
    ["Brute"] = {"BuggyQuest1",2},
    ["Desert Bandit"] = {"DesertQuest",1},
    ["Desert Officer"] = {"DesertQuest",2},
    ["Snow Bandit"] = {"SnowQuest",1},
    ["Snowman"] = {"SnowQuest",2},
    ["Chief Petty Officer"] = {"MarineQuest2",1},
    ["Sky Bandit"] = {"SkyQuest",1},
    ["Dark Master"] = {"SkyQuest",2},
}

local function hasQuest()
    local gui=LocalPlayer.PlayerGui:FindFirstChild("Main")
    if gui and gui:FindFirstChild("Quest") then
        return gui.Quest.Visible
    end
    return false
end

local function abandonQuest()
    pcall(function()
        CommF:InvokeServer("AbandonQuest")
    end)
end

local function startMappedQuest()
    local q=QuestMap[Config.SelectedMob]
    if not q then return false end

    local ok=pcall(function()
        CommF:InvokeServer(
            "StartQuest",
            q[1],
            q[2]
        )
    end)

    return ok
end

local function findNearestQuestNPC()
    local root=hrp()
    if not root then return nil end

    local best=nil
    local dist=nil

    for _,v in ipairs(
        Workspace:GetDescendants()
    ) do

        if v:IsA("ProximityPrompt") then

            local model=v.Parent and v.Parent.Parent

            if model and model:IsA("Model") then

                local part=
                    model:FindFirstChild("HumanoidRootPart")
                    or model:FindFirstChildWhichIsA("BasePart")

                if part then
                    local d=(
                        part.Position-root.Position
                    ).Magnitude

                    if not dist or d<dist then
                        dist=d
                        best=model
                    end
                end
            end
        end
    end

    return best
end

local function usePromptQuest()
    if not Config.SavedQuestNPC then
        Config.SavedQuestNPC=
            findNearestQuestNPC()
    end

    local npc=Config.SavedQuestNPC
    if not npc then return end

    local part=
        npc:FindFirstChild("HumanoidRootPart")
        or npc:FindFirstChildWhichIsA("BasePart")

    if not part then return end

    pcall(function()

        hrp().CFrame=
            part.CFrame*CFrame.new(0,0,4)

        task.wait(.4)

        for _,v in ipairs(
            npc:GetDescendants()
        ) do
            if v:IsA("ProximityPrompt") then
                fireproximityprompt(v)
            end
        end

    end)
end

local LastQuestAttempt=0

local function useQuestNPC()

    if hasQuest() then
        return
    end

    if tick()-LastQuestAttempt<3 then
        return
    end

    LastQuestAttempt=tick()

    abandonQuest()

    task.wait(.25)

    if not startMappedQuest() then
        usePromptQuest()
    end

end

------------------------------------------------
-- STABILITY
------------------------------------------------

local function sessionRefresh()

if not Config.SessionRefresh then
return
end

if (os.clock()-LastRefresh)/60
>=Config.RefreshMinutes then

pcall(function()
TeleportService:Teleport(
PlaceId,
LocalPlayer
)
end)

LastRefresh=os.clock()

end

end

local function stuckFix()

if not Config.AutoStuckFix then
return
end

local root=hrp()
if not root then return end

if Config.LastPos then

local moved=(
root.Position-Config.LastPos
).Magnitude

if moved<2 then

if os.clock()-Config.LastMoveTick>30 then
root.CFrame=root.CFrame*CFrame.new(
0,15,0
)
Config.LastMoveTick=os.clock()
end

else

Config.LastMoveTick=os.clock()

end
end

Config.LastPos=root.Position

end

